// 三层架构示意：DMA Circular 模式 + 环形缓冲区
// 第 1 层：硬件抽象
#define DMA_RX_BUF_SIZE  256

__attribute__((section(".dma_buf"))) 
volatile uint8_t dma_rx_buf[DMA_RX_BUF_SIZE];

// 第 2 层：环形缓冲区接口
static volatile uint16_t rb_read_pos = 0;

// 获取 DMA 已写入的字节数（通过 CNDTR 寄存器反推）
static inline uint16_t dma_get_transferred_count(DMA_TypeDef* dma, uint32_t channel) {
    uint32_t remaining = 0;
    if (dma == DMA1) remaining = dma->Channel[channel].CNDTR;
    else remaining = dma->Channel[channel].CNDTR;
    return DMA_RX_BUF_SIZE - (uint16_t)remaining;
}

// 环形缓冲区消费接口：逐字节取出
static inline bool ring_buffer_get(uint8_t* out) {
    uint16_t pos = rb_read_pos;
    if (pos == dma_get_transferred_count(DMA1, DMA_CHANNEL_5)) {
        return false;  // 无数据
    }
    *out = dma_rx_buf[pos % DMA_RX_BUF_SIZE];
    rb_read_pos++;
    return true;
}

// 第 3 层：DMA 中断回调
void DMA1_Channel5_IRQHandler(void) {
    if (__HAL_DMA_GET_FLAG(&hdma_usart1_rx, DMA_FLAG_TC5)) {
        // 全传输完成：DMA 已填满缓冲区，应用层可在主循环中消费
        __HAL_DMA_CLEAR_FLAG(&hdma_usart1_rx, DMA_FLAG_TC5);
        // 可选：通知 FreeRTOS 任务有数据可读
        // xNotificationFromISR();
    }
}

/* dma_ring_buffer.h - 头文件定义 */
#ifndef DMA_RING_BUFFER_H
#define DMA_RING_BUFFER_H

#include <stdint.h>
#include <stdbool.h>

#define DMA_BUF_SIZE    256      /* 必须是 2 的幂，方便位运算优化 */
#define DMA_BUF_MASK    (DMA_BUF_SIZE - 1)  /* = 0xFF */

/* DMA 缓冲区 —— 放在 DMA 友好区域 */
static uint8_t dma_rx_buf[DMA_BUF_SIZE];
static volatile uint16_t dma_transfer_count = 0;  /* 已传输字节数 */
static volatile uint16_t rb_read_pos = 0;          /* 应用层读指针 */

/* 函数声明 */
void dma_ring_buffer_init(void);
void DMA1_Channel5_IRQHandler_Custom(void);
uint16_t ring_buffer_extract_frame(uint8_t* frame_buf, uint16_t max_len);

#endif /* DMA_RING_BUFFER_H */

/* dma_ring_buffer.c - 实现 */
#include "dma_ring_buffer.h"
#include "stm32f1xx_hal.h"

static DMA_HandleTypeDef hdma_usart1_rx;

void dma_ring_buffer_init(void)
{
    /* 1. 初始化 DMA 通道 (假设已在 MX_DMA_Init 中完成) */
    /* 2. 启动 DMA 循环接收 */
    HAL_DMA_Start_IT(&hdma_usart1_rx,
                     (uint32_t)&huart1.Instance->DR,
                     (uint32_t)dma_rx_buf,
                     DMA_BUF_SIZE);
    /* 启动后 CNDTR = 256，每传输 1 字节减 1 */
}

/* 注意：实际项目中此 IRQ Handler 在 stm32f1xx_it.c 中 */
/* 中断优先级设置：NVIC_SetPriority(DMA1_Channel5_IRQn, 1); */
/* 清除标志顺序：先判断标志，再清除，最后处理数据 */
void DMA1_Channel5_IRQHandler_Custom(void)
{
    /* 读取 DMA_CNDTR 的快照 —— 读一次存到局部变量！ */
    /* 参考：《C陷阱与缺陷》—— 不要在同一表达式内重复读取易变寄存器 */
    uint16_t remaining = hdma_usart1_rx.Instance->CNDTR;

    /* 更新已传输字节数 */
    dma_transfer_count = DMA_BUF_SIZE - remaining;

    /* 清除 DMA 传输完成标志位 */
    __HAL_DMA_CLEAR_FLAG(&hdma_usart1_rx, DMA_FLAG_TC5);

    /* 注意：HAL 库默认不会自动重装 CNDTR 在 Circular 模式下 */
    /* CIRC 位由 HAL_DMA_Start_IT() 设置，硬件自动循环 */
    /* 但 dma_transfer_count 是软件累加的，不会自动重置 */
    /* 需要在上层消费时处理 wrap-around */
}

/* 陷阱 1 演示：CNDTR 的正确读取方式 */

/* 错误方式：先清标志再读 CNDTR */
void bad_dma_handler(void)
{
    __HAL_DMA_CLEAR_FLAG(&hdma, DMA_FLAG_TC5);  /* 先清标志！错误！ */
    uint16_t remaining = hdma.Instance->CNDTR;  /* 此时 DMA 可能还在传输 */
    uint16_t transferred = BUF_SIZE - remaining;
    process_data(transferred);  /* transferred 可能偏小 1-2 字节 */
}

/* 正确方式：先读 CNDTR 再清标志 */
void good_dma_handler(void)
{
    uint16_t remaining = hdma.Instance->CNDTR;  /* 先读！锁定快照 */
    uint16_t transferred = BUF_SIZE - remaining;
    __HAL_DMA_CLEAR_FLAG(&hdma, DMA_FLAG_TC5);  /* 再清标志 */
    process_data(transferred);  /* transferred 精确反映传输完成量 */
}

/* 陷阱 2 演示：非 2 的幂缓冲区的取模开销 */

/* 错误：缓冲区大小 100（非 2 的幂） */
#define BAD_BUF_SIZE 100
uint8_t bad_buf[BAD_BUF_SIZE];
uint16_t idx = 0;
// 每次索引操作: bad_buf[idx % BAD_BUF_SIZE] 生成 __aeabi_uidiv 调用
// 每条调用 ≈ 120-200 cycles @ 72MHz ≈ 1.7-2.8μs

/* 正确：缓冲区大小 128（2 的幂） */
#define GOOD_BUF_SIZE 128
#define GOOD_BUF_MASK (GOOD_BUF_SIZE - 1)  /* 0x7F */
uint8_t good_buf[GOOD_BUF_SIZE];
uint16_t idx = 0;
// 每次索引操作: good_buf[idx & GOOD_BUF_MASK] 生成 AND 指令
// 每条指令 1 cycle @ 72MHz ≈ 13.9ns
// 性能差距: 约 100-200 倍

/* 陷阱 3 演示：跨缓冲区回绕的帧提取 */

/* 错误：简单减法，溢出后结果为负数（无符号环绕） */
uint16_t bad_available(uint16_t total, uint16_t read) {
    if (total >= read) return total - read;  /* 总线的情况漏掉了！ */
    return 0;  /* 当 total < read 时直接返回 0，丢数据！ */
}

/* 正确：使用模 65536 语义处理回绕 */
uint16_t good_available(uint16_t total, uint16_t read) {
    return (total - read) & 0xFFFF;  /* 自动处理所有回绕情况 */
}

