/* ===== 重构后：结构化环形缓冲区 ===== */

#include <stdint.h>
#include <stdbool.h>
#include <string.h>

typedef struct {
    uint8_t*    data;       /* 环形缓冲区指针 */
    uint16_t    size;       /* 缓冲区总大小（2 的幂） */
    uint16_t    mask;       /* size - 1，用于位运算取模 */
    volatile uint16_t head; /* DMA 写入位置（由 DMA CNDTR 反推） */
    volatile uint16_t tail; /* 应用层读取位置 */
} ring_buffer_t;

/* 初始化环形缓冲区 */
static uint8_t dma_raw_buf[256];
static ring_buffer_t uart_rb = {
    .data = dma_raw_buf,
    .size = 256,
    .mask = 255  /* 256 - 1 */
};

/* 获取 DMA 已传输字节数 —— 只读，无副作用 */
static inline uint16_t rb_available(ring_buffer_t* rb)
{
    uint16_t head = (rb->size - (uint16_t)dma_stream->CNDTR) & 0xFFFF;
    /* 注意：CNDTR 读一次后可能被 DMA 修改，所以用 & 0xFFFF 保护回绕 */
    return (head - rb->tail) & 0xFFFF;  /* 模 65536 的减法，自动处理回绕 */
}

/* 提取完整帧（以 0x0A 为结束符），零拷贝：直接从 DMA 缓冲区返回指针 */
/* 返回：帧数据指针，或 NULL 表示无完整帧 */
static inline const uint8_t* rb_extract_frame(ring_buffer_t* rb,
                                              uint16_t* out_len)
{
    uint16_t avail = rb_available(rb);
    if (avail == 0) return NULL;

    /* 在缓冲区中寻找结束符 0x0A */
    const uint8_t* start = &rb->data[rb->tail & rb->mask];
    const uint8_t* end = memchr(start, 0x0A, avail);  /* 搜索帧结束符 */

    if (end == NULL) {
        /* 缓冲区中无完整帧，返回 NULL —— 主循环会继续等待 */
        return NULL;
    }

    /* 找到完整帧 */
    *out_len = (uint16_t)(end - start) + 1;  /* 包含 0x0A */
    rb->tail = (uint16_t)(rb->tail + *out_len) & 0xFFFF;

    /* 返回帧数据指针（零拷贝！帧数据就在 DMA 缓冲区中） */
    return start;
}

/* DMA 回调 —— 现在只更新 head，不做任何数据解析 */
void DMA1_Channel5_IRQHandler(void)
{
    if (__HAL_DMA_GET_FLAG(&hdma_usart1_rx, DMA_FLAG_TC5)) {
        __HAL_DMA_CLEAR_FLAG(&hdma_usart1_rx, DMA_FLAG_TC5);
        /* 不在此处处理数据！数据消费移到主循环 */
        /* 通知任务有数据到达 */
        BaseType_t xHigherPriorityTaskWoken = pdFALSE;
        vTaskNotifyGiveFromISR(uart_task_handle, &xHigherPriorityTaskWoken);
        portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
    }
}
